import{_ as t,c as p,b as o,a as n,d as a,e as l,r as c,o as i}from"./app-CvT2DUHU.js";const u={},r={href:"https://github.com/coolclaws/deerflow-book",target:"_blank",rel:"noopener noreferrer"};function d(k,s){const e=c("ExternalLinkIcon");return i(),p("div",null,[s[2]||(s[2]=o(`<h1 id="第-9-章-subagentexecutor-执行引擎" tabindex="-1"><a class="header-anchor" href="#第-9-章-subagentexecutor-执行引擎"><span>第 9 章　SubagentExecutor：执行引擎</span></a></h1><p>上一章从架构层面介绍了 Sub-Agent 的整体设计。本章将深入 <code>SubagentExecutor</code> 的实现细节，剖析它如何通过双线程池架构、状态机管理和超时控制来可靠地执行子任务。</p><p>所有核心代码都集中在 <code>backend/src/subagents/executor.py</code> 这一个文件中，代码量不到 500 行，但麻雀虽小五脏俱全。</p><h2 id="_9-1-subagentstatus-状态机" tabindex="-1"><a class="header-anchor" href="#_9-1-subagentstatus-状态机"><span>9.1 SubagentStatus 状态机</span></a></h2><p>每个 Sub-Agent 任务都有一个明确的生命周期，由 <code>SubagentStatus</code> 枚举定义：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">SubagentStatus</span><span class="token punctuation">(</span>Enum<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    PENDING <span class="token operator">=</span> <span class="token string">&quot;pending&quot;</span></span>
<span class="line">    RUNNING <span class="token operator">=</span> <span class="token string">&quot;running&quot;</span></span>
<span class="line">    COMPLETED <span class="token operator">=</span> <span class="token string">&quot;completed&quot;</span></span>
<span class="line">    FAILED <span class="token operator">=</span> <span class="token string">&quot;failed&quot;</span></span>
<span class="line">    TIMED_OUT <span class="token operator">=</span> <span class="token string">&quot;timed_out&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>状态转换路径如下：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text" data-title="text"><pre><code><span class="line">PENDING → RUNNING → COMPLETED</span>
<span class="line">                  → FAILED</span>
<span class="line">                  → TIMED_OUT</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>PENDING</code> 表示任务已提交但尚未开始执行；<code>RUNNING</code> 表示已进入执行线程池；三个终态分别对应成功完成、执行异常和超时中断。</p><p>这种设计确保了每个任务在任何时刻都有一个确定的状态，避免了状态模糊导致的并发问题。</p><h2 id="_9-2-subagentresult-数据结构" tabindex="-1"><a class="header-anchor" href="#_9-2-subagentresult-数据结构"><span>9.2 SubagentResult 数据结构</span></a></h2><p><code>SubagentResult</code> 是 Sub-Agent 执行的完整记录：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token decorator annotation punctuation">@dataclass</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">SubagentResult</span><span class="token punctuation">:</span></span>
<span class="line">    task_id<span class="token punctuation">:</span> <span class="token builtin">str</span></span>
<span class="line">    trace_id<span class="token punctuation">:</span> <span class="token builtin">str</span></span>
<span class="line">    status<span class="token punctuation">:</span> SubagentStatus</span>
<span class="line">    result<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span></span>
<span class="line">    error<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span></span>
<span class="line">    started_at<span class="token punctuation">:</span> datetime <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span></span>
<span class="line">    completed_at<span class="token punctuation">:</span> datetime <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span></span>
<span class="line">    ai_messages<span class="token punctuation">:</span> <span class="token builtin">list</span><span class="token punctuation">[</span><span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">,</span> Any<span class="token punctuation">]</span><span class="token punctuation">]</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">__post_init__</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">if</span> self<span class="token punctuation">.</span>ai_messages <span class="token keyword">is</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">            self<span class="token punctuation">.</span>ai_messages <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>几个关键字段的用途：</p><ul><li><code>task_id</code>：唯一任务标识，由 <code>tool_call_id</code> 传入，便于与 Lead Agent 的工具调用关联</li><li><code>trace_id</code>：分布式追踪 ID，贯穿父子 Agent 的所有日志</li><li><code>ai_messages</code>：执行过程中产生的所有 AI 消息列表，用于向前端实时推送进度</li><li><code>started_at</code> / <code>completed_at</code>：时间戳，用于性能分析和超时判断</li></ul><p>注意 <code>__post_init__</code> 中对 <code>ai_messages</code> 的处理——这是 Python dataclass 处理可变默认值的标准做法，避免了多个实例共享同一个列表对象的经典陷阱。</p><h2 id="_9-3-双线程池架构" tabindex="-1"><a class="header-anchor" href="#_9-3-双线程池架构"><span>9.3 双线程池架构</span></a></h2><p><code>SubagentExecutor</code> 最具特色的设计是双线程池分离：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token comment"># 调度线程池：负责任务编排和超时控制</span></span>
<span class="line">_scheduler_pool <span class="token operator">=</span> ThreadPoolExecutor<span class="token punctuation">(</span></span>
<span class="line">    max_workers<span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">,</span> thread_name_prefix<span class="token operator">=</span><span class="token string">&quot;subagent-scheduler-&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 执行线程池：负责实际的 Agent 执行</span></span>
<span class="line">_execution_pool <span class="token operator">=</span> ThreadPoolExecutor<span class="token punctuation">(</span></span>
<span class="line">    max_workers<span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">,</span> thread_name_prefix<span class="token operator">=</span><span class="token string">&quot;subagent-exec-&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>为什么需要两个线程池？因为超时控制需要一个&quot;看门人&quot;。如果调度和执行在同一个线程中，当执行超时时没有第二个线程来中断它。双线程池的工作流程是：</p><ol><li><code>task_tool</code> 调用 <code>execute_async()</code>，将任务提交到 <strong>scheduler 池</strong></li><li>scheduler 线程将任务提交到 <strong>execution 池</strong>，并调用 <code>future.result(timeout=...)</code> 等待</li><li>如果 execution 线程在超时时间内完成，scheduler 收集结果</li><li>如果超时，scheduler 捕获 <code>FuturesTimeoutError</code>，将状态设为 <code>TIMED_OUT</code></li></ol><p>来看 <code>execute_async</code> 的核心逻辑：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">def</span> <span class="token function">execute_async</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> task<span class="token punctuation">:</span> <span class="token builtin">str</span><span class="token punctuation">,</span> task_id<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token builtin">str</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">if</span> task_id <span class="token keyword">is</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        task_id <span class="token operator">=</span> <span class="token builtin">str</span><span class="token punctuation">(</span>uuid<span class="token punctuation">.</span>uuid4<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">[</span><span class="token punctuation">:</span><span class="token number">8</span><span class="token punctuation">]</span></span>
<span class="line"></span>
<span class="line">    result <span class="token operator">=</span> SubagentResult<span class="token punctuation">(</span></span>
<span class="line">        task_id<span class="token operator">=</span>task_id<span class="token punctuation">,</span></span>
<span class="line">        trace_id<span class="token operator">=</span>self<span class="token punctuation">.</span>trace_id<span class="token punctuation">,</span></span>
<span class="line">        status<span class="token operator">=</span>SubagentStatus<span class="token punctuation">.</span>PENDING<span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">with</span> _background_tasks_lock<span class="token punctuation">:</span></span>
<span class="line">        _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span> <span class="token operator">=</span> result</span>
<span class="line"></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">run_task</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">with</span> _background_tasks_lock<span class="token punctuation">:</span></span>
<span class="line">            _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span><span class="token punctuation">.</span>status <span class="token operator">=</span> SubagentStatus<span class="token punctuation">.</span>RUNNING</span>
<span class="line">            _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span><span class="token punctuation">.</span>started_at <span class="token operator">=</span> datetime<span class="token punctuation">.</span>now<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">            result_holder <span class="token operator">=</span> _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span></span>
<span class="line"></span>
<span class="line">        <span class="token keyword">try</span><span class="token punctuation">:</span></span>
<span class="line">            execution_future<span class="token punctuation">:</span> Future <span class="token operator">=</span> _execution_pool<span class="token punctuation">.</span>submit<span class="token punctuation">(</span></span>
<span class="line">                self<span class="token punctuation">.</span>execute<span class="token punctuation">,</span> task<span class="token punctuation">,</span> result_holder</span>
<span class="line">            <span class="token punctuation">)</span></span>
<span class="line">            <span class="token keyword">try</span><span class="token punctuation">:</span></span>
<span class="line">                exec_result <span class="token operator">=</span> execution_future<span class="token punctuation">.</span>result<span class="token punctuation">(</span></span>
<span class="line">                    timeout<span class="token operator">=</span>self<span class="token punctuation">.</span>config<span class="token punctuation">.</span>timeout_seconds</span>
<span class="line">                <span class="token punctuation">)</span></span>
<span class="line">                <span class="token keyword">with</span> _background_tasks_lock<span class="token punctuation">:</span></span>
<span class="line">                    _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span><span class="token punctuation">.</span>status <span class="token operator">=</span> exec_result<span class="token punctuation">.</span>status</span>
<span class="line">                    _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span><span class="token punctuation">.</span>result <span class="token operator">=</span> exec_result<span class="token punctuation">.</span>result</span>
<span class="line">                    _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span><span class="token punctuation">.</span>error <span class="token operator">=</span> exec_result<span class="token punctuation">.</span>error</span>
<span class="line">                    _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span><span class="token punctuation">.</span>completed_at <span class="token operator">=</span> datetime<span class="token punctuation">.</span>now<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">                    _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span><span class="token punctuation">.</span>ai_messages <span class="token operator">=</span> exec_result<span class="token punctuation">.</span>ai_messages</span>
<span class="line">            <span class="token keyword">except</span> FuturesTimeoutError<span class="token punctuation">:</span></span>
<span class="line">                <span class="token keyword">with</span> _background_tasks_lock<span class="token punctuation">:</span></span>
<span class="line">                    _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span><span class="token punctuation">.</span>status <span class="token operator">=</span> SubagentStatus<span class="token punctuation">.</span>TIMED_OUT</span>
<span class="line">                    _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span><span class="token punctuation">.</span>error <span class="token operator">=</span> <span class="token punctuation">(</span></span>
<span class="line">                        <span class="token string-interpolation"><span class="token string">f&quot;Execution timed out after &quot;</span></span></span>
<span class="line">                        <span class="token string-interpolation"><span class="token string">f&quot;</span><span class="token interpolation"><span class="token punctuation">{</span>self<span class="token punctuation">.</span>config<span class="token punctuation">.</span>timeout_seconds<span class="token punctuation">}</span></span><span class="token string"> seconds&quot;</span></span></span>
<span class="line">                    <span class="token punctuation">)</span></span>
<span class="line">                    _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span><span class="token punctuation">.</span>completed_at <span class="token operator">=</span> datetime<span class="token punctuation">.</span>now<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">                execution_future<span class="token punctuation">.</span>cancel<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">except</span> Exception <span class="token keyword">as</span> e<span class="token punctuation">:</span></span>
<span class="line">            <span class="token keyword">with</span> _background_tasks_lock<span class="token punctuation">:</span></span>
<span class="line">                _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span><span class="token punctuation">.</span>status <span class="token operator">=</span> SubagentStatus<span class="token punctuation">.</span>FAILED</span>
<span class="line">                _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span><span class="token punctuation">.</span>error <span class="token operator">=</span> <span class="token builtin">str</span><span class="token punctuation">(</span>e<span class="token punctuation">)</span></span>
<span class="line">                _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span><span class="token punctuation">.</span>completed_at <span class="token operator">=</span> datetime<span class="token punctuation">.</span>now<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    _scheduler_pool<span class="token punctuation">.</span>submit<span class="token punctuation">(</span>run_task<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span> task_id</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>整个流程中，<code>_background_tasks_lock</code> 确保了对共享状态字典的线程安全访问。每次状态更新都在锁内完成，避免了读写竞争。</p><h2 id="_9-4-同步执行与异步桥接" tabindex="-1"><a class="header-anchor" href="#_9-4-同步执行与异步桥接"><span>9.4 同步执行与异步桥接</span></a></h2><p><code>execute</code> 方法是同步与异步的桥接层：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">def</span> <span class="token function">execute</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> task<span class="token punctuation">:</span> <span class="token builtin">str</span><span class="token punctuation">,</span> result_holder<span class="token punctuation">:</span> SubagentResult <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> SubagentResult<span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">try</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> asyncio<span class="token punctuation">.</span>run<span class="token punctuation">(</span>self<span class="token punctuation">.</span>_aexecute<span class="token punctuation">(</span>task<span class="token punctuation">,</span> result_holder<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">except</span> Exception <span class="token keyword">as</span> e<span class="token punctuation">:</span></span>
<span class="line">        logger<span class="token punctuation">.</span>exception<span class="token punctuation">(</span><span class="token string-interpolation"><span class="token string">f&quot;[trace=</span><span class="token interpolation"><span class="token punctuation">{</span>self<span class="token punctuation">.</span>trace_id<span class="token punctuation">}</span></span><span class="token string">] execution failed&quot;</span></span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">if</span> result_holder <span class="token keyword">is</span> <span class="token keyword">not</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">            result <span class="token operator">=</span> result_holder</span>
<span class="line">        <span class="token keyword">else</span><span class="token punctuation">:</span></span>
<span class="line">            result <span class="token operator">=</span> SubagentResult<span class="token punctuation">(</span></span>
<span class="line">                task_id<span class="token operator">=</span><span class="token builtin">str</span><span class="token punctuation">(</span>uuid<span class="token punctuation">.</span>uuid4<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">[</span><span class="token punctuation">:</span><span class="token number">8</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">                trace_id<span class="token operator">=</span>self<span class="token punctuation">.</span>trace_id<span class="token punctuation">,</span></span>
<span class="line">                status<span class="token operator">=</span>SubagentStatus<span class="token punctuation">.</span>FAILED<span class="token punctuation">,</span></span>
<span class="line">            <span class="token punctuation">)</span></span>
<span class="line">        result<span class="token punctuation">.</span>status <span class="token operator">=</span> SubagentStatus<span class="token punctuation">.</span>FAILED</span>
<span class="line">        result<span class="token punctuation">.</span>error <span class="token operator">=</span> <span class="token builtin">str</span><span class="token punctuation">(</span>e<span class="token punctuation">)</span></span>
<span class="line">        result<span class="token punctuation">.</span>completed_at <span class="token operator">=</span> datetime<span class="token punctuation">.</span>now<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">return</span> result</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里使用 <code>asyncio.run()</code> 而非 <code>await</code>，因为执行线程池中的线程没有事件循环。<code>asyncio.run()</code> 会创建一个全新的事件循环来运行异步代码，这使得 Sub-Agent 可以使用异步工具（如 MCP 工具）。</p><p><code>_aexecute</code> 方法使用 <code>astream</code> 以流式方式获取 Agent 的执行过程，每产生一条新的 <code>AIMessage</code> 就追加到 <code>result.ai_messages</code> 列表中。由于 <code>result_holder</code> 是从全局 <code>_background_tasks</code> 字典中取出的引用，更新会实时反映到轮询方查看的数据中。</p><h2 id="_9-5-任务轮询与进度推送" tabindex="-1"><a class="header-anchor" href="#_9-5-任务轮询与进度推送"><span>9.5 任务轮询与进度推送</span></a></h2><p><code>task_tool</code> 中的轮询循环每 5 秒检查一次任务状态：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">while</span> <span class="token boolean">True</span><span class="token punctuation">:</span></span>
<span class="line">    result <span class="token operator">=</span> get_background_task_result<span class="token punctuation">(</span>task_id<span class="token punctuation">)</span></span>
<span class="line">    <span class="token comment"># ...检查新消息，推送 task_running 事件...</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">if</span> result<span class="token punctuation">.</span>status <span class="token operator">==</span> SubagentStatus<span class="token punctuation">.</span>COMPLETED<span class="token punctuation">:</span></span>
<span class="line">        writer<span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token string">&quot;type&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;task_completed&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;task_id&quot;</span><span class="token punctuation">:</span> task_id<span class="token punctuation">,</span> <span class="token string">&quot;result&quot;</span><span class="token punctuation">:</span> result<span class="token punctuation">.</span>result<span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line">        cleanup_background_task<span class="token punctuation">(</span>task_id<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token string-interpolation"><span class="token string">f&quot;Task Succeeded. Result: </span><span class="token interpolation"><span class="token punctuation">{</span>result<span class="token punctuation">.</span>result<span class="token punctuation">}</span></span><span class="token string">&quot;</span></span></span>
<span class="line">    <span class="token keyword">elif</span> result<span class="token punctuation">.</span>status <span class="token operator">==</span> SubagentStatus<span class="token punctuation">.</span>FAILED<span class="token punctuation">:</span></span>
<span class="line">        <span class="token comment"># ...</span></span>
<span class="line">    <span class="token keyword">elif</span> result<span class="token punctuation">.</span>status <span class="token operator">==</span> SubagentStatus<span class="token punctuation">.</span>TIMED_OUT<span class="token punctuation">:</span></span>
<span class="line">        <span class="token comment"># ...</span></span>
<span class="line"></span>
<span class="line">    time<span class="token punctuation">.</span>sleep<span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span></span>
<span class="line">    poll_count <span class="token operator">+=</span> <span class="token number">1</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">if</span> poll_count <span class="token operator">&gt;</span> max_poll_count<span class="token punctuation">:</span></span>
<span class="line">        <span class="token comment"># 安全网：防止线程池超时机制失效时无限等待</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token string-interpolation"><span class="token string">f&quot;Task polling timed out...&quot;</span></span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>轮询过程中，每当检测到新的 AI 消息，会通过 <code>stream_writer</code> 向前端推送 <code>task_running</code> 事件，实现实时进度展示。<code>max_poll_count</code> 作为安全网，设置为 <code>(timeout_seconds + 60) / 5</code>，在执行超时加 60 秒缓冲后强制结束轮询。</p><h2 id="_9-6-background-task-清理" tabindex="-1"><a class="header-anchor" href="#_9-6-background-task-清理"><span>9.6 Background Task 清理</span></a></h2><p>为防止内存泄漏，完成的任务需要从全局字典中清除：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">def</span> <span class="token function">cleanup_background_task</span><span class="token punctuation">(</span>task_id<span class="token punctuation">:</span> <span class="token builtin">str</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">with</span> _background_tasks_lock<span class="token punctuation">:</span></span>
<span class="line">        result <span class="token operator">=</span> _background_tasks<span class="token punctuation">.</span>get<span class="token punctuation">(</span>task_id<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">if</span> result <span class="token keyword">is</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token keyword">return</span></span>
<span class="line"></span>
<span class="line">        is_terminal_status <span class="token operator">=</span> result<span class="token punctuation">.</span>status <span class="token keyword">in</span> <span class="token punctuation">{</span></span>
<span class="line">            SubagentStatus<span class="token punctuation">.</span>COMPLETED<span class="token punctuation">,</span></span>
<span class="line">            SubagentStatus<span class="token punctuation">.</span>FAILED<span class="token punctuation">,</span></span>
<span class="line">            SubagentStatus<span class="token punctuation">.</span>TIMED_OUT<span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">        <span class="token keyword">if</span> is_terminal_status <span class="token keyword">or</span> result<span class="token punctuation">.</span>completed_at <span class="token keyword">is</span> <span class="token keyword">not</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token keyword">del</span> _background_tasks<span class="token punctuation">[</span>task_id<span class="token punctuation">]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>清理只在终态时执行，这个检查避免了一种竞态条件：如果轮询线程在 scheduler 线程更新状态之前就尝试清理，可能会删除一个仍在运行的任务条目。通过检查是否处于终态，确保了清理操作的安全性。</p><h2 id="_9-7-错误处理的三层防护" tabindex="-1"><a class="header-anchor" href="#_9-7-错误处理的三层防护"><span>9.7 错误处理的三层防护</span></a></h2><p>Sub-Agent 的错误处理设计了三层防护网：</p><ol><li><strong>Agent 执行层</strong>（<code>_aexecute</code>）：<code>try-except</code> 捕获 Agent 运行中的所有异常，设置 <code>FAILED</code> 状态</li><li><strong>事件循环层</strong>（<code>execute</code>）：捕获 <code>asyncio.run()</code> 自身的失败，如在已有事件循环的上下文中调用</li><li><strong>调度层</strong>（<code>execute_async</code> 中的 <code>run_task</code>）：捕获线程提交和超时相关的异常</li></ol><p>无论异常发生在哪一层，最终都会被正确记录到 <code>SubagentResult</code> 中，保证 <code>task_tool</code> 的轮询循环一定能收到一个终态结果。</p><h2 id="小结" tabindex="-1"><a class="header-anchor" href="#小结"><span>小结</span></a></h2><p><code>SubagentExecutor</code> 的实现虽然紧凑，但在可靠性方面做了充分的考量：</p><ul><li>双线程池分离调度与执行，使超时控制成为可能</li><li>五状态机（PENDING / RUNNING / COMPLETED / FAILED / TIMED_OUT）覆盖了所有生命周期</li><li><code>SubagentResult</code> 承载执行的完整记录，包括实时 AI 消息</li><li><code>asyncio.run()</code> 桥接同步线程池与异步 Agent 执行</li><li>全局字典 + 线程锁实现线程安全的状态共享</li><li>三层错误处理确保任何异常都不会导致任务&quot;消失&quot;</li><li>终态检查的清理机制防止内存泄漏和竞态条件</li></ul><p>下一章将跳出执行引擎的视角，看看 Lead Agent 如何通过 Middleware 和 Prompt 工程来编排多个 Sub-Agent 的并发调度。</p><hr>`,46)),n("p",null,[s[1]||(s[1]=a("来源: ",-1)),n("a",r,[s[0]||(s[0]=a("DeerFlow Book",-1)),l(e)])])])}const b=t(u,[["render",d]]),m=JSON.parse('{"path":"/docs/Agent/DeerFlow/09-subagent-executor.html","title":"第 9 章　SubagentExecutor：执行引擎","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"9.1 SubagentStatus 状态机","slug":"_9-1-subagentstatus-状态机","link":"#_9-1-subagentstatus-状态机","children":[]},{"level":2,"title":"9.2 SubagentResult 数据结构","slug":"_9-2-subagentresult-数据结构","link":"#_9-2-subagentresult-数据结构","children":[]},{"level":2,"title":"9.3 双线程池架构","slug":"_9-3-双线程池架构","link":"#_9-3-双线程池架构","children":[]},{"level":2,"title":"9.4 同步执行与异步桥接","slug":"_9-4-同步执行与异步桥接","link":"#_9-4-同步执行与异步桥接","children":[]},{"level":2,"title":"9.5 任务轮询与进度推送","slug":"_9-5-任务轮询与进度推送","link":"#_9-5-任务轮询与进度推送","children":[]},{"level":2,"title":"9.6 Background Task 清理","slug":"_9-6-background-task-清理","link":"#_9-6-background-task-清理","children":[]},{"level":2,"title":"9.7 错误处理的三层防护","slug":"_9-7-错误处理的三层防护","link":"#_9-7-错误处理的三层防护","children":[]},{"level":2,"title":"小结","slug":"小结","link":"#小结","children":[]}],"git":{},"filePathRelative":"docs/Agent/DeerFlow/09-subagent-executor.md"}');export{b as comp,m as data};
